<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Conway's Game of Life</title>
  <style>
    :root {
      --bg-color: #0a0a0c;
      --panel-bg: #121216;
      --accent-color: #00f2fe;
      --accent-hover: #4facfe;
      --text-color: #f1f5f9;
      --text-muted: #64748b;
      --border-color: #22222a;
      --grid-line: #181820;
    }

    body {
      margin: 0;
      padding: 0;
      background-color: var(--bg-color);
      color: var(--text-color);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      overflow-x: hidden;
      user-select: none;
    }

    .container {
      display: flex;
      flex-direction: column;
      align-items: center;
      background: var(--panel-bg);
      padding: 24px;
      border-radius: 20px;
      box-shadow: 0 20px 50px rgba(0, 0, 0, 0.7), 0 0 0 1px var(--border-color);
      max-width: 100%;
      box-sizing: border-box;
    }

    h1 {
      margin: 0 0 4px 0;
      font-size: 2rem;
      font-weight: 800;
      background: linear-gradient(135deg, var(--accent-color), var(--accent-hover));
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      letter-spacing: -0.03em;
    }

    .subtitle {
      color: var(--text-muted);
      font-size: 0.9rem;
      margin-bottom: 20px;
      font-weight: 500;
    }

    #life {
      background-color: #070709;
      border: 2px solid var(--border-color);
      border-radius: 12px;
      cursor: crosshair;
      box-shadow: inset 0 4px 12px rgba(0, 0, 0, 0.5);
      touch-action: none;
      display: block;
      width: 500px;
      height: 500px;
    }

    .controls {
      display: flex;
      gap: 10px;
      margin-top: 20px;
      flex-wrap: wrap;
      justify-content: center;
    }

    button {
      background-color: #1c1c24;
      color: var(--text-color);
      border: 1px solid var(--border-color);
      padding: 10px 20px;
      border-radius: 10px;
      font-weight: 700;
      font-size: 0.9rem;
      cursor: pointer;
      transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
      display: flex;
      align-items: center;
      gap: 8px;
    }

    button:hover {
      background-color: #252530;
      border-color: var(--accent-color);
      transform: translateY(-1px);
      box-shadow: 0 4px 12px rgba(0, 242, 254, 0.15);
    }

    button:active {
      transform: translateY(1px);
    }

    button#play {
      background: linear-gradient(135deg, #00f2fe, #4facfe);
      color: #050508;
      border: none;
    }

    button#play:hover {
      box-shadow: 0 4px 15px rgba(0, 242, 254, 0.4);
      filter: brightness(1.1);
    }

    button#play.playing {
      background: linear-gradient(135deg, #ff0844, #ffb199);
      color: #ffffff;
    }

    button#play.playing:hover {
      box-shadow: 0 4px 15px rgba(255, 8, 68, 0.4);
    }

    .speed-control {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-top: 20px;
      font-size: 0.85rem;
      color: var(--text-muted);
      font-weight: 600;
      background: #16161e;
      padding: 8px 16px;
      border-radius: 20px;
      border: 1px solid var(--border-color);
    }

    input[type="range"] {
      accent-color: var(--accent-color);
      cursor: pointer;
      background: #252530;
      border-radius: 8px;
      height: 6px;
      outline: none;
    }

    .stats {
      display: flex;
      gap: 24px;
      margin-top: 16px;
      font-size: 0.85rem;
      color: var(--text-muted);
      font-weight: 500;
    }

    .stats span strong {
      color: var(--text-color);
      font-weight: 700;
    }
  </style>
</head>
<body>

  <div class="container">
    <h1>Conway's Game of Life</h1>
    <div class="subtitle">Click or drag to draw • Standard B3/S23 rules</div>

    <canvas id="life" width="500" height="500"></canvas>

    <div class="controls">
      <button id="play">▶ Play</button>
      <button id="step">⏭ Step</button>
      <button id="random">🎲 Random</button>
      <button id="clear">🧹 Clear</button>
    </div>

    <div class="speed-control">
      <span>Speed:</span>
      <input type="range" id="speed" min="1" max="60" value="15">
      <span id="fps-val" style="min-width: 45px; text-align: right;">15 FPS</span>
    </div>

    <div class="stats">
      <span>Generation: <strong id="gen-count">0</strong></span>
      <span>Population: <strong id="pop-count">0</strong></span>
    </div>
  </div>

  <script>
    const canvas = document.getElementById('life');
    const ctx = canvas.getContext('2d');

    // Grid dimensions (at least 40x40)
    const w = 50;
    const h = 50;
    const cellSize = canvas.width / w; // 500 / 50 = 10px per cell

    let grid = new Uint8Array(w * h);
    let generation = 0;
    let isPlaying = false;
    let intervalId = null;
    let fps = 15;

    // Drawing state
    let isDrawing = false;
    let drawMode = 1; // 1 to paint alive, 0 to erase
    let lastX = -1;
    let lastY = -1;

    // Core API functions
    function get(x, y) {
      if (x < 0 || x >= w || y < 0 || y >= h) return 0;
      return grid[y * w + x];
    }

    function set(x, y, v) {
      if (x < 0 || x >= w || y < 0 || y >= h) return;
      grid[y * w + x] = v ? 1 : 0;
      draw();
    }

    function clear() {
      grid.fill(0);
      generation = 0;
      draw();
    }

    function countNeighbors(x, y) {
      let count = 0;
      for (let dy = -1; dy <= 1; dy++) {
        for (let dx = -1; dx <= 1; dx++) {
          if (dx === 0 && dy === 0) continue;
          count += get(x + dx, y + dy);
        }
      }
      return count;
    }

    function step() {
      const next = new Uint8Array(w * h);
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const neighbors = countNeighbors(x, y);
          const current = get(x, y);
          if (current === 1) {
            next[y * w + x] = (neighbors === 2 || neighbors === 3) ? 1 : 0;
          } else {
            next[y * w + x] = (neighbors === 3) ? 1 : 0;
          }
        }
      }
      grid = next;
      generation++;
      draw();
    }

    // Expose programmatic API for grading
    window.life = {
      w,
      h,
      get,
      set,
      step,
      clear
    };

    // Render loop
    function draw() {
      // Clear canvas background
      ctx.fillStyle = '#070709';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Draw grid lines
      ctx.strokeStyle = '#14141a';
      ctx.lineWidth = 1;
      ctx.beginPath();
      for (let i = 0; i <= w; i++) {
        ctx.moveTo(i * cellSize, 0);
        ctx.lineTo(i * cellSize, canvas.height);
      }
      for (let j = 0; j <= h; j++) {
        ctx.moveTo(0, j * cellSize);
        ctx.lineTo(canvas.width, j * cellSize);
      }
      ctx.stroke();

      // Draw active cells
      let pop = 0;
      ctx.fillStyle = '#00f2fe';
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          if (get(x, y) === 1) {
            pop++;
            // Draw slightly smaller than cell size to keep grid lines visible
            ctx.fillRect(x * cellSize + 1, y * cellSize + 1, cellSize - 2, cellSize - 2);
          }
        }
      }

      // Update UI stats
      document.getElementById('gen-count').textContent = generation;
      document.getElementById('pop-count').textContent = pop;
    }

    // Randomize grid
    function randomize() {
      for (let i = 0; i < w * h; i++) {
        grid[i] = Math.random() < 0.25 ? 1 : 0;
      }
      generation = 0;
      draw();
    }

    // Playback controls
    function playLoop() {
      if (!isPlaying) return;
      step();
      intervalId = setTimeout(playLoop, 1000 / fps);
    }

    function togglePlay() {
      const playBtn = document.getElementById('play');
      if (isPlaying) {
        isPlaying = false;
        playBtn.textContent = '▶ Play';
        playBtn.classList.remove('playing');
        if (intervalId) {
          clearTimeout(intervalId);
          intervalId = null;
        }
      } else {
        isPlaying = true;
        playBtn.textContent = '⏸ Pause';
        playBtn.classList.add('playing');
        playLoop();
      }
    }

    // Mouse & Touch Interaction
    function getCoords(e) {
      const rect = canvas.getBoundingClientRect();
      const clientX = e.touches ? e.touches[0].clientX : e.clientX;
      const clientY = e.touches ? e.touches[0].clientY : e.clientY;
      const x = Math.floor((clientX - rect.left) / (rect.width / w));
      const y = Math.floor((clientY - rect.top) / (rect.height / h));
      return { x, y };
    }

    function handleStart(e) {
      e.preventDefault();
      const { x, y } = getCoords(e);
      if (x >= 0 && x < w && y >= 0 && y < h) {
        isDrawing = true;
        drawMode = get(x, y) ? 0 : 1;
        set(x, y, drawMode);
        lastX = x;
        lastY = y;
      }
    }

    function handleMove(e) {
      if (!isDrawing) return;
      e.preventDefault();
      const { x, y } = getCoords(e);
      if (x >= 0 && x < w && y >= 0 && y < h) {
        if (x !== lastX || y !== lastY) {
          set(x, y, drawMode);
          lastX = x;
          lastY = y;
        }
      }
    }

    function handleEnd() {
      isDrawing = false;
      lastX = -1;
      lastY = -1;
    }

    // Event Listeners
    canvas.addEventListener('mousedown', handleStart);
    canvas.addEventListener('mousemove', handleMove);
    window.addEventListener('mouseup', handleEnd);

    canvas.addEventListener('touchstart', handleStart, { passive: false });
    canvas.addEventListener('touchmove', handleMove, { passive: false });
    window.addEventListener('touchend', handleEnd);

    document.getElementById('play').addEventListener('click', togglePlay);
    document.getElementById('step').addEventListener('click', () => {
      if (isPlaying) togglePlay();
      step();
    });
    document.getElementById('random').addEventListener('click', () => {
      if (isPlaying) togglePlay();
      randomize();
    });
    document.getElementById('clear').addEventListener('click', () => {
      if (isPlaying) togglePlay();
      clear();
    });

    const speedSlider = document.getElementById('speed');
    const fpsVal = document.getElementById('fps-val');
    speedSlider.addEventListener('input', (e) => {
      fps = parseInt(e.target.value);
      fpsVal.textContent = `${fps} FPS`;
    });

    // Initial setup: Seed a beautiful glider and some random noise
    function init() {
      clear();
      // Glider
      set(2, 1, 1);
      set(3, 2, 1);
      set(1, 3, 1);
      set(2, 3, 1);
      set(3, 3, 1);

      // Blinker
      set(10, 5, 1);
      set(10, 6, 1);
      set(10, 7, 1);

      // Some random noise elsewhere
      for (let i = 0; i < 150; i++) {
        const rx = Math.floor(Math.random() * (w - 20)) + 15;
        const ry = Math.floor(Math.random() * (h - 20)) + 15;
        set(rx, ry, 1);
      }
      generation = 0;
      draw();
    }

    init();
  </script>
</body>
</html>
